class LogicalClock:
    def __init__(self, initial_ms: int) -> None:
        self._now_ms = initial_ms
        self._lock = threading.RLock()

    def get(self) -> int:
        with self._lock:
            return self._now_ms

    def set(self, now_ms: int) -> int:
        with self._lock:
            if now_ms < self._now_ms:
                raise ServiceError(409, "clock_rewind", "logical clock cannot move backwards")
            self._now_ms = now_ms
            return self._now_ms

    @contextmanager
    def stable_now(self) -> Iterator[int]:
        with self._lock:
            yield self._now_ms


