                415,
                "unsupported_media_type",
                "request content type must be application/json",
            )
            await response(scope, receive, send)
            return

        chunks: list[bytes] = []
        while True:
            message = await receive()
            message_type = _message_type(message)
            if message_type == "http.disconnect":
                return
            if message_type != "http.request":
                raise RuntimeError("unexpected ASGI message while reading request")
            chunks.append(_message_body(message))
            if not _message_more_body(message):
                break
        body = b"".join(chunks)
        try:
            json.loads(body, parse_constant=_reject_json_constant)
        except ValueError:
            response = _error_response(400, "invalid_json", "request body is not valid JSON")
            await response(scope, receive, send)
            return

        delivered = False

        async def replay_receive() -> Message:
            nonlocal delivered
            if delivered:
                return {"type": "http.disconnect"}
            delivered = True
            return {"type": "http.request", "body": body, "more_body": False}

        await self._app(scope, replay_receive, send)


def create_app(database_path: str, initial_clock_ms: int) -> FastAPI:
    store = SQLiteStore(database_path)
    clock = LogicalClock(initial_clock_ms)
    app = FastAPI(title="Q1/L1 Lease Job Service", version="1.0.0")
    app.add_middleware(JsonRequestMiddleware)

    @app.exception_handler(ServiceError)
    async def service_error_handler(request: Request, exc: ServiceError) -> JSONResponse:
        return _error_response(exc.status_code, exc.code, exc.message)

    @app.exception_handler(RequestValidationError)
    async def request_validation_handler(
        request: Request, exc: RequestValidationError
    ) -> JSONResponse:
        return _error_response(422, "validation_error", "request does not match the contract")

    @app.get("/healthz", response_model=Health)
    async def healthz() -> Health:
        return Health(status="ok", contract_version="1.0.0")

    @app.get("/_evaluator/clock", response_model=Clock)
    async def get_clock() -> Clock:
        return Clock(now_ms=clock.get())

    @app.put("/_evaluator/clock", response_model=Clock)
    async def set_clock(body: Clock) -> Clock:
        return Clock(now_ms=clock.set(body.now_ms))

    @app.post("/v1/jobs", response_model=Job)
    async def submit_job(body: SubmitJobRequest, response: Response) -> Job:
        with clock.stable_now() as now_ms:
            submission = store.submit(body.idempotency_key, body.payload, now_ms)
        response.status_code = 201 if submission.created else 200
        return submission.job

    @app.get("/v1/jobs/{job_id}", response_model=Job)
    async def get_job(job_id: str) -> Job:
        canonical_id = _canonical_job_id(job_id)
        with clock.stable_now() as now_ms:
            job = store.get(canonical_id, now_ms)
        if job is None:
            raise ServiceError(404, "job_not_found", "job was not found")
        return job

    @app.post("/v1/leases", response_model=LeaseGrant)
    async def acquire_lease(body: AcquireLeaseRequest, response: Response) -> LeaseGrant | Response:
        with clock.stable_now() as now_ms:
            grant = store.acquire(body.worker_id, body.ttl_ms, now_ms)
        if grant is None:
            response.status_code = 204
            return Response(status_code=204)
        return grant

    @app.post("/v1/jobs/{job_id}/heartbeat", response_model=Job)
    async def heartbeat_lease(job_id: str, body: HeartbeatRequest) -> Job:
        canonical_id = _canonical_job_id(job_id)
        with clock.stable_now() as now_ms:
            return store.heartbeat(canonical_id, body.lease_token, body.ttl_ms, now_ms)

    @app.post("/v1/jobs/{job_id}/complete", response_model=Job)
    async def complete_job(job_id: str, body: CompleteJobRequest) -> Job:
        canonical_id = _canonical_job_id(job_id)
        with clock.stable_now() as now_ms:
            return store.complete(canonical_id, body.lease_token, body.result, now_ms)

    @app.post("/v1/jobs/{job_id}/fail", response_model=Job)
    async def fail_job(job_id: str, body: FailJobRequest) -> Job:
        canonical_id = _canonical_job_id(job_id)
        with clock.stable_now() as now_ms:
            return store.fail(canonical_id, body.lease_token, body.failure, now_ms)

    return app


app = create_app(
    _required_environment("Q1_L1_DATABASE_PATH"),
    _parse_nonnegative_int(
        _required_environment("Q1_L1_CLOCK_INITIAL_MS"), "Q1_L1_CLOCK_INITIAL_MS"
    ),
)


def run() -> None:
    uvicorn.run(
        app,
        host=_required_environment("Q1_L1_HOST"),
        port=_parse_port(_required_environment("Q1_L1_PORT")),
        log_level="warning",
    )


if __name__ == "__main__":
    run()
